const d = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const wfId = (d.workflow?.id || 'unknown');
const lastNode = (d.execution?.lastNodeExecuted || 'unknown');
const key = `${wfId}|${lastNode}`;

if (staticData.lastErrorKey === key) {
  const lastTime = staticData.lastErrorTime || 0;
  const now = Date.now();
  if (now - lastTime < 300000) return []; // 5 min cooldown per workflow+node
}

staticData.lastErrorKey = key;
staticData.lastErrorTime = Date.now();
return [$input.first()];

const d = $input.first().json;
const wfName  = (d.workflow?.name  || 'Unknown workflow');
const wfId    = (d.workflow?.id    || '');
const errMsg  = (d.execution?.error?.message || 'Unknown error').substring(0, 200);
const lastNode = (d.execution?.lastNodeExecuted || 'unknown node');
const execId  = (d.execution?.id   || '');

return [{json: {
  wfName,
  errMsg: errMsg.substring(0, 150),
  lastNode: lastNode.substring(0, 50),
  taskTitle: `SpaceShipIO: ${wfName} failed`,
  taskBody: `Workflow: ${wfName}\nExecution: ${execId}\nFailed at: ${lastNode}\n\nError: ${errMsg}`,
  idemKey: `spaceship-err-${wfId}`
}}];
